+/**
+ * Email notification adapter — delivers notifications via email.
+ *
+ * This is a stub implementation that logs email sends in-memory.
+ * Replace the send() internals with a real email transport (SMTP, SES, etc.)
+ * while keeping the NotificationAdapter interface contract.
+ */
+
+import type { NotificationAdapter } from './notification.adapter.js';
+import type { NotificationPayload, NotificationResult } from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+export interface EmailConfig {
+  /** SMTP host or email service endpoint */
+  host: string;
+  /** SMTP port */
+  port: number;
+  /** Sender email address */
+  from: string;
+}
+
+export const defaultEmailConfig: EmailConfig = {
+  host: 'localhost',
+  port: 587,
+  from: 'noreply@taskflowpro.example',
+};
+
+export class EmailNotificationAdapter implements NotificationAdapter {
+  readonly channel = 'email' as const;
+  private logger = new Logger('EmailAdapter');
+  private sentEmails: NotificationPayload[] = [];
+
+  constructor(private config: EmailConfig = defaultEmailConfig) {}
+
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    this.logger.info(
+      `Sending email to ${payload.recipient}: "${payload.subject}"`,
+    );
+
+    // Stub: store in memory instead of actually sending
+    this.sentEmails.push(payload);
+
+    this.logger.info(
+      `Email delivered: ${payload.id} from ${this.config.from} to ${payload.recipient}`,
+    );
+
+    return {
+      notificationId: payload.id,
+      channel: 'email',
+      success: true,
+      deliveredAt: new Date(),
+    };
+  }
+
+  /**
+   * Get all emails sent through this adapter (for testing).
+   */
+  getSentEmails(): NotificationPayload[] {
+    return [...this.sentEmails];
+  }
+
+  /**
+   * Clear sent emails log (for testing).
+   */
+  clearSentEmails(): void {
+    this.sentEmails = [];
+  }
+}

