+/**
+ * Notification model — core types for the notification system.
+ *
+ * Architecture: Event-driven via EventBus.
+ * Flow: Event Producer → EventBus → NotificationService → NotificationAdapter(s)
+ *
+ * Constraints:
+ * - All adapters must implement the NotificationAdapter interface
+ * - All notifications must originate from EventBus events
+ * - New channels are added by registering new adapters, not by modifying the service
+ */
+
+/**
+ * Supported notification channels. Each channel corresponds to a NotificationAdapter.
+ */
+export type NotificationChannel = 'email' | 'webhook' | 'in-app' | 'sms';
+
+/**
+ * Notification types that the system can send.
+ * Maps to business events — extend this union as new notification triggers are added.
+ */
+export type NotificationType =
+  | 'order-confirmation'
+  | 'order-status-update'
+  | 'welcome'
+  | 'account-updated';
+
+/**
+ * Priority levels for notification delivery.
+ */
+export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';
+
+/**
+ * The payload passed to notification adapters for delivery.
+ */
+export interface NotificationPayload {
+  /** Unique notification ID */
+  id: string;
+  /** The type of notification being sent */
+  type: NotificationType;
+  /** Delivery channel */
+  channel: NotificationChannel;
+  /** Recipient identifier (email address, user ID, webhook URL, etc.) */
+  recipient: string;
+  /** Notification subject / title */
+  subject: string;
+  /** Notification body content */
+  body: string;
+  /** Delivery priority */
+  priority: NotificationPriority;
+  /** When the notification was created */
+  createdAt: Date;
+  /** Arbitrary metadata for adapter-specific needs */
+  metadata?: Record<string, unknown>;
+}
+
+/**
+ * Result of a notification delivery attempt.
+ */
+export interface NotificationResult {
+  /** The notification that was sent */
+  notificationId: string;
+  /** The channel that handled delivery */
+  channel: NotificationChannel;
+  /** Whether delivery succeeded */
+  success: boolean;
+  /** Error message if delivery failed */
+  error?: string;
+  /** Timestamp of delivery attempt */
+  deliveredAt: Date;
+}
+
+/**
+ * A persisted notification record.
+ */
+export interface Notification {
+  id: string;
+  type: NotificationType;
+  channel: NotificationChannel;
+  recipient: string;
+  subject: string;
+  body: string;
+  priority: NotificationPriority;
+  success: boolean;
+  error?: string;
+  createdAt: Date;
+  deliveredAt?: Date;
+}

