parameters.content:
/**
 * Notification model — core types for the notification system.
 *
 * Architecture: Event-driven via EventBus.
 * Flow: Event Producer → EventBus → NotificationService → NotificationAdapter(s)
 *
 * Constraints:
 * - All adapters must implement the NotificationAdapter interface
 * - All notifications must originate from EventBus events
 * - New channels are added by registering new adapters, not by modifying the service
 */

/**
 * Supported notification channels. Each channel corresponds to a NotificationAdapter.
 */
export type NotificationChannel = 'email' | 'webhook' | 'in-app' | 'sms';

/**
 * Notification types that the system can send.
 * Maps to business events — extend this union as new notification triggers are added.
 */
export type NotificationType =
  | 'order-confirmation'
  | 'order-status-update'
  | 'welcome'
  | 'account-updated';

/**
 * Priority levels for notification delivery.
 */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';

/**
 * The payload passed to notification adapters for delivery.
 */
export interface NotificationPayload {
  /** Unique notification ID */
  id: string;
  /** The type of notification being sent */
  type: NotificationType;
  /** Delivery channel */
  channel: NotificationChannel;
  /** Recipient identifier (email address, user ID, webhook URL, etc.) */
  recipient: string;
  /** Notification subject / title */
  subject: string;
  /** Notification body content */
  body: string;
  /** Delivery priority */
  priority: NotificationPriority;
  /** When the notification was created */
  createdAt: Date;
  /** Arbitrary metadata for adapter-specific needs */
  metadata?: Record<string, unknown>;
}

/**
 * Result of a notification delivery attempt.
 */
export interface NotificationResult {
  /** The notification that was sent */
  notificationId: string;
  /** The channel that handled delivery */
  channel: NotificationChannel;
  /** Whether delivery succeeded */
  success: boolean;
  /** Error message if delivery failed */
  error?: string;
  /** Timestamp of delivery attempt */
  deliveredAt: Date;
}

/**
 * A persisted notification record.
 */
export interface Notification {
  id: string;
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  priority: NotificationPriority;
  success: boolean;
  error?: string;
  createdAt: Date;
  deliveredAt?: Date;
}

/**
 * NotificationAdapter — interface that all notification channel adapters must implement.
 *
 * Architecture constraint: New notification channels (email, SMS, webhook, in-app)
 * are added by creating a new class implementing this interface and registering it
 * with the NotificationService. Do NOT add channel-specific logic to the service itself.
 *
 * Flow: NotificationService receives events → builds NotificationPayload → dispatches
 * to the adapter registered for the payload's channel.
 */

import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';

/**
 * All notification adapters must implement this interface.
 *
 * Each adapter handles delivery for exactly one NotificationChannel.
 * The adapter is responsible for:
 * 1. Transforming the NotificationPayload into channel-specific format
 * 2. Delivering the notification via the channel's transport
 * 3. Returning a NotificationResult indicating success or failure
 */
export interface NotificationAdapter {
  /** The channel this adapter handles */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this adapter's channel.
   * Must not throw — return a failed NotificationResult instead.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs email sends in-memory.
 * Replace the send() internals with a real email transport (SMTP, SES, etc.)
 * while keeping the NotificationAdapter interface contract.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  /** SMTP host or email service endpoint */
  host: string;
  /** SMTP port */
  port: number;
  /** Sender email address */
  from: string;
}

export const defaultEmailConfig: EmailConfig = {
  host: 'localhost',
  port: 587,
  from: 'noreply@taskflowpro.example',
};

export class EmailNotificationAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: NotificationPayload[] = [];

  constructor(private config: EmailConfig = defaultEmailConfig) {}

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(
      `Sending email to ${payload.recipient}: "${payload.subject}"`,
    );

    // Stub: store in memory instead of actually sending
    this.sentEmails.push(payload);

    this.logger.info(
      `Email delivered: ${payload.id} from ${this.config.from} to ${payload.recipient}`,
    );

    return {
      notificationId: payload.id,
      channel: 'email',
      success: true,
      deliveredAt: new Date(),
    };
  }

  /**
   * Get all emails sent through this adapter (for testing).
   */
  getSentEmails(): NotificationPayload[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails log (for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — sends notifications in response to EventBus events.
 *
 * Architecture: Event-driven, single pattern.
 * All events arrive via EventBus subscriptions. Delivery is delegated to
 * NotificationAdapter implementations (one per channel).
 *
 * Flow: EventBus event → NotificationService handler → adapter.send()
 *
 * Constraints:
 * - ALL notification triggers must come through EventBus (no direct calls, no CallbackRegistry)
 * - ALL delivery goes through registered NotificationAdapters
 * - New channels = new adapter + registerAdapter(), NOT changes to this service
 * - New event types = new handler + EventBus subscription in registerEventHandlers()
 *
 * Depends on:
 * - EventBus (event system) for receiving all events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  NotificationPayload,
  NotificationResult,
  NotificationType,
  NotificationPriority,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private notifications: Notification[] = [];

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a specific channel.
   * Only one adapter per channel — later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to all events that should trigger notifications.
   * Add new subscriptions here when new notification-worthy events are created.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      return this.handleUserCreated(event);
    });
  }

  /**
   * Handle order created — send confirmation to the ordering user.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.send({
      type: 'order-confirmation',
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      priority: 'normal',
    });
  }

  /**
   * Handle order status change — notify user of the update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    await this.send({
      type: 'order-status-update',
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      priority: 'normal',
    });
  }

  /**
   * Handle user created — send welcome notification.
   */
  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    await this.send({
      type: 'welcome',
      channel: 'email',
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro',
      body: `Hi ${event.user.name}, welcome to TaskFlow Pro!`,
      priority: 'low',
    });
  }

  /**
   * Send a notification through the appropriate adapter.
   * This is the single delivery path — all notifications go through here.
   */
  async send(params: {
    type: NotificationType;
    channel: NotificationChannel;
    recipient: string;
    subject: string;
    body: string;
    priority: NotificationPriority;
    metadata?: Record<string, unknown>;
  }): Promise<NotificationResult> {
    const payload: NotificationPayload = {
      id: generateNotificationId(),
      type: params.type,
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      priority: params.priority,
      createdAt: new Date(),
      metadata: params.metadata,
    };

    const adapter = this.adapters.get(params.channel);

    if (!adapter) {
      this.logger.warn(
        `No adapter registered for channel "${params.channel}" — notification ${payload.id} dropped`,
      );
      const record: Notification = {
        ...payload,
        success: false,
        error: `No adapter for channel: ${params.channel}`,
      };
      this.notifications.push(record);
      return {
        notificationId: payload.id,
        channel: params.channel,
        success: false,
        error: `No adapter for channel: ${params.channel}`,
        deliveredAt: new Date(),
      };
    }

    this.logger.info(`Sending ${params.type} notification via ${params.channel} to ${params.recipient}`);
    const result = await adapter.send(payload);

    const record: Notification = {
      ...payload,
      success: result.success,
      error: result.error,
      deliveredAt: result.deliveredAt,
    };
    this.notifications.push(record);

    return result;
  }

  /**
   * Get all notification records.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notification records (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

